<?php
namespace App\Modules\Hr\Recruitment\Actions;use App\Modules\Hr\Core\Services\HrAuditService;use App\Modules\Hr\Core\Services\TenantContext;use App\Modules\Hr\Recruitment\Models\HrApplication;use App\Modules\Hr\Recruitment\Models\HrApplicationStage;use Illuminate\Support\Facades\DB;
class AdvanceApplicationAction{private const STAGES=['applied','screening','interview','reference','offer'];public function __construct(private HrAuditService $audit){}public function execute(HrApplication $application,string $stage,?float $score=null,?string $notes=null):HrApplication{abort_unless(auth()->user()?->hasHrPermission('hr.recruitment.manage_candidates'),403);abort_unless($application->legal_entity_id===app(TenantContext::class)->getId()&&$application->status==='active',404);$current=array_search($application->current_stage,self::STAGES,true);$next=array_search($stage,self::STAGES,true);abort_unless($current!==false&&$next===$current+1,422,'Aday yalnızca sıradaki aşamaya geçirilebilir.');abort_if($score!==null&&($score<0||$score>100),422);return DB::transaction(function()use($application,$stage,$score,$notes,$next){$row=HrApplication::withoutGlobalScope('tenant')->whereKey($application->id)->lockForUpdate()->firstOrFail();HrApplicationStage::create(['legal_entity_id'=>$row->legal_entity_id,'application_id'=>$row->id,'stage'=>$stage,'sequence'=>$next+1,'status'=>'completed','score'=>$score,'notes'=>$notes,'completed_at'=>now(),'acted_by'=>auth()->id()]);$row->update(['current_stage'=>$stage,'human_score'=>$score??$row->human_score]);$this->audit->log('recruitment_application_advanced',$row,null,['stage'=>$stage,'score'=>$score]);return $row->fresh();});}public function reject(HrApplication $application,string $reason):HrApplication{abort_unless(auth()->user()?->hasHrPermission('hr.recruitment.manage_candidates'),403);abort_unless($application->legal_entity_id===app(TenantContext::class)->getId()&&$application->status==='active',404);abort_if(blank($reason),422,'İnsan tarafından girilmiş ret gerekçesi zorunludur.');$application->update(['status'=>'rejected','decision_reason'=>trim($reason),'decided_by'=>auth()->id(),'decided_at'=>now()]);$this->audit->log('recruitment_application_rejected',$application);return $application->fresh();}}
